import React, { useState, useEffect } from 'react';
import { PlusIcon, TrashIcon, EditIcon, CheckIcon, XIcon } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { RainbowButton } from '../ui/rainbow-button';
import { RainbowCard } from '../ui/rainbow-card';
import { RainbowInput } from '../ui/rainbow-input';

const TodoList = () => {
  const [todos, setTodos] = useState([]);
  const [newTodo, setNewTodo] = useState('');
  const [filter, setFilter] = useState('all'); // all, pending, completed
  const [editingId, setEditingId] = useState(null);
  const [editText, setEditText] = useState('');

  // 从localStorage加载待办事项
  useEffect(() => {
    const savedTodos = localStorage.getItem('personal-workspace-todos');
    if (savedTodos) {
      setTodos(JSON.parse(savedTodos));
    }
  }, []);

  // 保存待办事项到localStorage
  const saveTodos = (updatedTodos) => {
    localStorage.setItem('personal-workspace-todos', JSON.stringify(updatedTodos));
    setTodos(updatedTodos);
  };

  // 添加新任务
  const addTodo = () => {
    if (newTodo.trim() === '') return;
    
    const todo = {
      id: uuidv4(),
      text: newTodo.trim(),
      completed: false,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    
    const updatedTodos = [...todos, todo];
    saveTodos(updatedTodos);
    setNewTodo('');
  };

  // 切换完成状态
  const toggleTodo = (id) => {
    const updatedTodos = todos.map(todo =>
      todo.id === id
        ? { ...todo, completed: !todo.completed, updatedAt: new Date().toISOString() }
        : todo
    );
    saveTodos(updatedTodos);
  };

  // 删除任务
  const deleteTodo = (id) => {
    const updatedTodos = todos.filter(todo => todo.id !== id);
    saveTodos(updatedTodos);
  };

  // 开始编辑
  const startEdit = (id, text) => {
    setEditingId(id);
    setEditText(text);
  };

  // 保存编辑
  const saveEdit = () => {
    if (editText.trim() === '') {
      cancelEdit();
      return;
    }
    
    const updatedTodos = todos.map(todo =>
      todo.id === editingId
        ? { ...todo, text: editText.trim(), updatedAt: new Date().toISOString() }
        : todo
    );
    saveTodos(updatedTodos);
    setEditingId(null);
    setEditText('');
  };

  // 取消编辑
  const cancelEdit = () => {
    setEditingId(null);
    setEditText('');
  };

  // 处理回车键
  const handleKeyPress = (e, action) => {
    if (e.key === 'Enter') {
      action();
    }
  };

  // 过滤待办事项
  const filteredTodos = todos.filter(todo => {
    switch (filter) {
      case 'pending':
        return !todo.completed;
      case 'completed':
        return todo.completed;
      default:
        return true;
    }
  });

  // 统计信息
  const totalTodos = todos.length;
  const completedTodos = todos.filter(todo => todo.completed).length;
  const pendingTodos = totalTodos - completedTodos;

  return (
    <div className="h-full flex flex-col p-6">
      {/* 头部 */}
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900 mb-2">✅ 待办事项</h2>
        <p className="text-gray-600">管理您的日常任务和待办事项</p>
      </div>

      {/* 统计信息 */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 text-center">
          <div className="text-2xl font-bold text-blue-600">{totalTodos}</div>
          <div className="text-sm text-blue-600">总任务</div>
        </div>
        <div className="bg-orange-50 border border-orange-200 rounded-lg p-4 text-center">
          <div className="text-2xl font-bold text-orange-600">{pendingTodos}</div>
          <div className="text-sm text-orange-600">待完成</div>
        </div>
        <div className="bg-green-50 border border-green-200 rounded-lg p-4 text-center">
          <div className="text-2xl font-bold text-green-600">{completedTodos}</div>
          <div className="text-sm text-green-600">已完成</div>
        </div>
      </div>

      {/* 添加新任务 */}
      <div className="mb-6">
        <div className="flex space-x-2">
          <input
            type="text"
            value={newTodo}
            onChange={(e) => setNewTodo(e.target.value)}
            onKeyPress={(e) => handleKeyPress(e, addTodo)}
            placeholder="添加新任务..."
            className="flex-1 input-field"
          />
          <RainbowButton
            onClick={addTodo}
            className="flex items-center space-x-2"
          >
            <PlusIcon size={16} />
            <span>添加</span>
          </RainbowButton>
        </div>
      </div>

      {/* 筛选按钮 */}
      <div className="flex space-x-2 mb-6">
        <RainbowButton
          onClick={() => setFilter('all')}
          className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${filter === 'all' ? 'opacity-100' : 'opacity-70'}`}
        >
          全部 ({totalTodos})
        </RainbowButton>
        <RainbowButton
          onClick={() => setFilter('pending')}
          className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${filter === 'pending' ? 'opacity-100' : 'opacity-70'}`}
        >
          待办 ({pendingTodos})
        </RainbowButton>
        <RainbowButton
          onClick={() => setFilter('completed')}
          className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${filter === 'completed' ? 'opacity-100' : 'opacity-70'}`}
        >
          已完成 ({completedTodos})
        </RainbowButton>
      </div>

      {/* 任务列表 */}
      <div className="flex-1 overflow-y-auto">
        {filteredTodos.length === 0 ? (
          <div className="text-center py-12 text-gray-500">
            <div className="text-4xl mb-4">📝</div>
            <p className="text-lg mb-2">
              {filter === 'all' && '还没有任务'}
              {filter === 'pending' && '没有待办任务'}
              {filter === 'completed' && '没有已完成任务'}
            </p>
            <p className="text-sm">
              {filter === 'all' && '添加第一个任务开始管理您的待办事项'}
              {filter === 'pending' && '所有任务都已完成！'}
              {filter === 'completed' && '完成一些任务后会显示在这里'}
            </p>
          </div>
        ) : (
          <div className="space-y-2">
            {filteredTodos.map((todo) => (
              <div
                key={todo.id}
                className={`group flex items-center space-x-3 p-4 bg-white border rounded-lg transition-all hover:shadow-sm ${
                  todo.completed ? 'border-green-200 bg-green-50' : 'border-gray-200'
                }`}
              >
                {/* 复选框 */}
                <button
                  onClick={() => toggleTodo(todo.id)}
                  className={`flex-shrink-0 w-5 h-5 rounded border-2 flex items-center justify-center transition-colors ${
                    todo.completed
                      ? 'bg-green-500 border-green-500 text-white'
                      : 'border-gray-300 hover:border-green-400'
                  }`}
                >
                  {todo.completed && <CheckIcon size={12} />}
                </button>

                {/* 任务内容 */}
                <div className="flex-1 min-w-0">
                  {editingId === todo.id ? (
                    <div className="flex items-center space-x-2">
                      <input
                        type="text"
                        value={editText}
                        onChange={(e) => setEditText(e.target.value)}
                        onKeyPress={(e) => handleKeyPress(e, saveEdit)}
                        className="flex-1 px-2 py-1 border border-gray-300 rounded text-sm focus:outline-none focus:ring-2 focus:ring-primary-500"
                        autoFocus
                      />
                      <button
                        onClick={saveEdit}
                        className="p-1 text-green-600 hover:text-green-700"
                      >
                        <CheckIcon size={16} />
                      </button>
                      <button
                        onClick={cancelEdit}
                        className="p-1 text-gray-400 hover:text-gray-600"
                      >
                        <XIcon size={16} />
                      </button>
                    </div>
                  ) : (
                    <div
                      onDoubleClick={() => startEdit(todo.id, todo.text)}
                      className="cursor-pointer"
                    >
                      <p
                        className={`text-sm ${
                          todo.completed
                            ? 'line-through text-gray-500'
                            : 'text-gray-900'
                        }`}
                      >
                        {todo.text}
                      </p>
                      <p className="text-xs text-gray-400 mt-1">
                        {new Date(todo.updatedAt).toLocaleString()}
                      </p>
                    </div>
                  )}
                </div>

                {/* 操作按钮 */}
                {editingId !== todo.id && (
                  <div className="flex items-center space-x-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button
                      onClick={() => startEdit(todo.id, todo.text)}
                      className="p-1 text-gray-400 hover:text-blue-500 transition-colors"
                      title="编辑"
                    >
                      <EditIcon size={14} />
                    </button>
                    <button
                      onClick={() => deleteTodo(todo.id)}
                      className="p-1 text-gray-400 hover:text-red-500 transition-colors"
                      title="删除"
                    >
                      <TrashIcon size={14} />
                    </button>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default TodoList;
